sql:
SELECT c.name, c.url
FROM companies c
WHERE c.status = 'active' AND c.employee_count > 100;

external_knowledge:
- 'newer companies' refers to those founded after 2000;
- 'early stages of funding' refers to Seed or Series A rounds;
- 'substantial financial performance' means the companies have an average revenue over 1 million.

sql:
SELECT SUM(amount) AS total_funding
FROM funding
WHERE company_id = 10;
